/**
 * Gera public/js/panels-bundle.js a partir de public/components/*.html
 * Uso: node scripts/build-panels-bundle.js
 */
const fs = require('fs');
const path = require('path');

const root = path.join(__dirname, '..');
const dir = path.join(root, 'public', 'components');
const outFile = path.join(root, 'public', 'js', 'panels-bundle.js');

const map = {
  'auth-screen-container': 'auth-screen.html',
  'sidebar-container': 'sidebar.html',
  'view-dashboard-container': 'dashboard-panel.html',
  'view-download-container': 'sync-panel.html',
  'view-certificado-container': 'certificates-panel.html',
  'view-regras-container': 'rules-panel.html'
};

const out = {};
for (const [id, file] of Object.entries(map)) {
  // Keep generated output deterministic across Windows/Linux checkouts.
  out[id] = fs.readFileSync(path.join(dir, file), 'utf8').replace(/\r\n/g, '\n');
}

const js = `/* auto-generated by scripts/build-panels-bundle.js — do not edit */\nwindow.PANEL_HTML = ${JSON.stringify(out)};\n`;
fs.writeFileSync(outFile, js);
console.log(`OK: ${outFile} (${js.length} bytes)`);
